import { ref } from 'vue'
import { getAdminSupabaseClient } from '@/utils/supabase-admin'
import { callEdgeFunction, getEdgeFunctionsUrl } from '@/utils/supabase'

export interface SystemStatus {
    type: 'success' | 'warning' | 'danger' | 'info';
    text: string
}

export function useAdminSystemStatus() {
    const config = useRuntimeConfig()
    const session = useSupabaseSession()

    // Environment Info
    const isDev = process.env.NODE_ENV !== 'production'
    const supabaseUrl = config.public.supabaseUrl
    const edgeUrl = getEdgeFunctionsUrl()

    // Status State
    const dbStatus = ref<SystemStatus>({ type: 'info', text: 'Waiting...' })
    const r2Status = ref<SystemStatus>({ type: 'info', text: 'Waiting...' })
    const edgeStatus = ref<SystemStatus>({ type: 'info', text: 'Waiting...' })
    const checking = ref(false)

    // Check Functions
    const checkEdge = async () => {
        if (edgeUrl && edgeUrl.startsWith('http')) {
            edgeStatus.value = { type: 'success', text: 'Configured' }
        } else {
            edgeStatus.value = { type: 'warning', text: 'Not Configured' }
        }
    }

    const checkAll = async () => {
        checking.value = true
        dbStatus.value = { type: 'info', text: 'Checking...' }
        r2Status.value = { type: 'info', text: 'Checking...' }
        edgeStatus.value = { type: 'info', text: 'Checking...' }

        try {
            // Check Edge Config locally
            checkEdge()

            // Check DB & Storage via Server API
            const token = await getAuthToken()

            if (!token) {
                throw new Error('No active session token')
            }

            const { data, error } = await useFetch('/api/admin/system/status', {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            })

            if (error.value) {
                throw new Error(error.value.statusMessage || 'Network Error')
            }

            const result = data.value
            if (!result || !result.success) {
                throw new Error(result?.error || 'Check Failed')
            }

            // Update UI
            const res = result.results
            dbStatus.value = {
                type: res.db.status === 'success' ? 'success' : 'danger',
                text: res.db.message
            }
            r2Status.value = {
                type: res.storage.status === 'success' ? 'success' : 'danger',
                text: res.storage.message
            }

        } catch (e: any) {
            dbStatus.value = { type: 'danger', text: 'Error: ' + e.message }
            r2Status.value = { type: 'danger', text: 'Error: ' + e.message }
        } finally {
            checking.value = false
        }
    }

    return {
        isDev,
        supabaseUrl,
        edgeUrl,
        dbStatus,
        r2Status,
        edgeStatus,
        checking,
        checkAll
    }
}
<template>
  <div class="page-container">
    <PageTipHeader 
      title="系统信息" 
      description="查看当前系统服务运行状态及环境配置。" 
    />

    <div class="settings-dashboard">
      <el-card shadow="never" class="mb-4">
        <template #header>
          <div class="card-header">
            <span>系统信息</span>
            <el-tag type="success" size="small">正常运行</el-tag>
          </div>
        </template>
        <el-descriptions :column="2" border>
          <el-descriptions-item label="应用名称">凡图拉 Admin</el-descriptions-item>
          <el-descriptions-item label="当前环境">{{ isDev ? 'Development' : 'Production' }}</el-descriptions-item>
          <el-descriptions-item label="Supabase Url">{{ supabaseUrl }}</el-descriptions-item>
          <el-descriptions-item label="Edge Functions">{{ edgeUrl }}</el-descriptions-item>
        </el-descriptions>
      </el-card>

      <el-card shadow="never">
        <template #header>
          <div class="card-header">
            <span>服务连通性检测</span>
            <el-button type="primary" size="small" @click="checkAll" :loading="checking">重新检测</el-button>
          </div>
        </template>

        <div class="status-list">
          <div class="status-item">
            <div class="status-label">
              <el-icon><DataLine /></el-icon> Database Connection
            </div>
            <div class="status-value">
              <el-tag :type="dbStatus.type">{{ dbStatus.text }}</el-tag>
            </div>
          </div>

          <el-divider direction="horizontal" style="margin: 12px 0;" />

          <div class="status-item">
            <div class="status-label">
              <el-icon><Files /></el-icon> R2 Storage Connection
            </div>
            <div class="status-value">
              <el-tag :type="r2Status.type">{{ r2Status.text }}</el-tag>
            </div>
          </div>

          <el-divider direction="horizontal" style="margin: 12px 0;" />

          <div class="status-item">
             <div class="status-label">
                <el-icon><Service /></el-icon> Edge Function (Hello)
             </div>
             <div class="status-value">
                 <el-tag :type="edgeStatus.type">{{ edgeStatus.text }}</el-tag>
             </div>
          </div>
        </div>
      </el-card>
    </div>
  </div>
</template>

<script setup lang="ts">
import { onMounted } from 'vue'
import { DataLine, Files, Service } from '@element-plus/icons-vue'
import PageTipHeader from '@/components/admin/base/PageTipHeader.vue'
import { useAdminSystemStatus } from '@/composables/admin/useAdminSystemStatus'

definePageMeta({
  layout: 'mgmt',
  middleware: ["mgmt-auth"]
})

const { 
  isDev, 
  supabaseUrl, 
  edgeUrl, 
  dbStatus, 
  r2Status, 
  edgeStatus, 
  checking, 
  checkAll 
} = useAdminSystemStatus()

onMounted(() => {
    checkAll()
})
</script>

<style scoped>
.page-container {
    padding-bottom: 20px;
}
.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.status-list {
    display: flex;
    flex-direction: column;
}
.status-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 0;
}
.status-label {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 14px;
    color: var(--el-text-color-regular);
}
</style>
